external_knowledge:
young maidens under the age of 30 = females under 30 years old;
voyaged on the upper decks A or B = passengers on deck A or B;
embarked from the shores of Cherbourg = passengers who embarked from Cherbourg;
not as common travelers = not traveling in third class;
survival and sinking rate = survival rate and death rate;
ocean of life = metaphor for the journey of life on the ship;

sql:
SELECT name AS 'Passenger Name'
FROM passengers
WHERE fare > (SELECT AVG(fare) FROM passengers);

SELECT name
FROM passengers
WHERE survived = 1;

external_knowledge:
-elite passengers: refers to passengers in the first class;
-survival fates: refers to whether the passenger survived (1) or not (0);
-average survival wave: the average survival rate of passengers in the first class;

sql:
SELECT COUNT(*) AS number_of_survived_passengers_above_average_age
FROM passengers
WHERE survived = 1 AND age > (SELECT AVG(age) FROM passengers);

SELECT 
    (SELECT COUNT(*) FROM passengers WHERE class = 3 AND survived = 1) * 100.0 / 
    (SELECT COUNT(*) FROM passengers WHERE class = 3) AS survival_rate;

SELECT name 
FROM passengers
WHERE survived = 1 AND pclass = 1;

SELECT AVG(age) AS average_age
FROM crew_members
WHERE joined_date < '1920-01-01';

SELECT name
FROM passengers
WHERE age < 18 AND class = 1;

